import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.ObjectInputStream;

public class InsecureDeserializationExample {

    public static void main(String[] args) {
        String userInput = "rO0ABXNyACpvcmcuamF2YS5tYW5hZ2VyLlN5c3RlbQAAAAAAAAABAgACSQAK";
        byte[] serializedObject = userInput.getBytes();

        Object deserializedObject = deserialize(serializedObject);

        System.out.println("Deserialized object: " + deserializedObject);
    }

    private static Object deserialize(byte[] serializedData) {
        try {
            ByteArrayInputStream bis = new ByteArrayInputStream(serializedData);
            ObjectInputStream ois = new ObjectInputStream(bis);
            return ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
            return null;
        }
    }
}

